// SPDX-License-Identifier: MIT
pragma solidity 0.8.34;

import "../interfaces/IPunksAuction.sol";

/// @title  PunkLots
///
/// @notice Punk lots handled by the auction house. Each punk can be in one lot.
///
/// @dev    The concrete auction contract supplies the vault and market-specific
///         hooks used to validate custody and release reservations.
///
/// @author VV × 1001
abstract contract PunkLots is IPunksAuction {
    /// @notice Maximum Punks per lot.
    uint8 internal constant MAX_LOT_ITEMS = 80;
    /// @notice Total item weight expected across a lot.
    uint16 internal constant TOTAL_WEIGHT_BPS = 10_000;

    /// @notice Returns the last lot id that was created.
    uint256 public lastLotId;

    /// @notice Returns core data for a lot. Fetch items via `getLotItems`.
    mapping(uint256 => Lot) public lots;
    /// @notice Returns the active lot id holding a seller's Punk, or 0 if none.
    /// @dev    Keyed by `keccak256(seller, tokenContract, punkId)`. A non-zero
    ///         entry reserves that Punk for one lot at a time — first-wins.
    mapping(bytes32 => uint256) public lotForPunk;

    /// @dev Dynamic item arrays for stored lots, keyed by lot id.
    mapping(uint256 => LotItem[]) internal lotItems;

    // ─────────────────────────────────── Lots ───────────────────────────────────

    /// @inheritdoc IPunksAuction
    function createLot(
        LotItem[] calldata items,
        uint96 reserveWei,
        address onlySellTo
    ) external returns (uint256 id) {
        return _createLot(items, reserveWei, onlySellTo);
    }

    /// @inheritdoc IPunksAuction
    function updateLot(uint256 id, uint96 reserveWei, address onlySellTo) external {
        Lot storage lot = lots[id];
        if (lot.seller == address(0)) revert LotNotFound();
        if (lot.seller != msg.sender) revert NotSeller();
        if (reserveWei == 0) revert InvalidAmount();

        lot.reserveWei = reserveWei;
        lot.onlySellTo = onlySellTo;

        emit LotUpdated(id, reserveWei, onlySellTo);
    }

    /// @inheritdoc IPunksAuction
    function cancelLot(uint256 id) external {
        Lot storage lot = lots[id];
        if (lot.seller == address(0)) revert LotNotFound();
        if (lot.seller != msg.sender) revert NotSeller();

        _releaseLotSlots(lot.seller, lotItems[id]);
        delete lots[id];
        delete lotItems[id];

        emit LotCancelled(id);
    }

    /// @inheritdoc IPunksAuction
    function clearStaleLot(uint256 id) external {
        _clearStaleLot(id);
    }

    /// @inheritdoc IPunksAuction
    function clearStaleLots(uint256[] calldata ids) external {
        uint256 len = ids.length;
        for (uint256 i; i < len;) {
            _clearStaleLot(ids[i]);
            unchecked {
                ++i;
            }
        }
    }

    // ─────────────────────────────────── Views ──────────────────────────────────

    /// @inheritdoc IPunksAuction
    function getLotItems(uint256 lotId) external view returns (LotItem[] memory) {
        return lotItems[lotId];
    }

    /// @notice Returns the active lot id holding a seller's Punk, or 0 if none.
    function activeLotFor(address seller, TokenStandard standard, uint16 punkId)
        external
        view
        returns (uint256)
    {
        return lotForPunk[_tokenKey(seller, _tokenContractFor(standard), punkId)];
    }

    // ───────────────────────────────── Internals ─────────────────────────────────

    /// @dev Creates a lot of `items` owned by `msg.sender`. Pre-checks that the
    ///      seller's vault is deployed and has approved this contract as
    ///      operator, surfacing misconfiguration up front.
    function _createLot(
        LotItem[] calldata items,
        uint96 reserveWei,
        address onlySellTo
    ) internal returns (uint256 id) {
        if (reserveWei == 0) revert InvalidAmount();
        _requireAuctionApproved(msg.sender);
        _validateLotItems(items);

        uint8 itemCount = uint8(items.length);

        unchecked {
            id = ++lastLotId;
        }

        lots[id] = Lot({
            seller: msg.sender,
            reserveWei: reserveWei,
            onlySellTo: onlySellTo
        });

        emit LotCreated(
            id,
            msg.sender,
            keccak256(abi.encode(items)),
            itemCount,
            reserveWei,
            onlySellTo
        );

        LotItem[] storage storedItems = lotItems[id];
        for (uint256 i; i < itemCount;) {
            LotItem calldata item = items[i];
            storedItems.push(item);
            bytes32 key = _tokenKey(msg.sender, _tokenContractFor(item.standard), item.punkId);
            lotForPunk[key] = id;
            emit LotItemDetail(id, uint8(i), item.standard, item.punkId, item.weightBps);
            unchecked {
                ++i;
            }
        }
    }

    /// @dev Removes a lot that is no longer approved or whose custody slipped
    ///      out of the vault.
    function _clearStaleLot(uint256 id) internal {
        Lot memory lot = lots[id];
        if (lot.seller == address(0)) revert LotNotFound();

        LotItem[] memory items = lotItems[id];
        bool stale = !_auctionIsApproved(lot.seller);
        if (!stale) {
            uint256 itemCount = items.length;
            for (uint256 i; i < itemCount;) {
                if (!_punkInSellerVault(items[i].standard, lot.seller, items[i].punkId)) {
                    stale = true;
                    break;
                }
                unchecked {
                    ++i;
                }
            }
        }
        if (!stale) revert LotNotStale();

        _releaseLotSlots(lot.seller, items);
        delete lots[id];
        delete lotItems[id];

        emit LotCleared(id, msg.sender);
    }

    /// @dev Validates lot items at create time: count, weights, duplicates,
    ///      vault custody, and per-item slot availability (one lot per Punk).
    function _validateLotItems(LotItem[] calldata items) internal view {
        uint256 n = items.length;
        if (n == 0 || n > MAX_LOT_ITEMS) revert InvalidItemCount();

        uint256 weightSum;
        for (uint256 i; i < n;) {
            uint16 w = items[i].weightBps;
            if (w == 0) revert InvalidWeights();
            weightSum += w;
            unchecked {
                ++i;
            }
        }
        if (weightSum != TOTAL_WEIGHT_BPS) revert InvalidWeights();

        for (uint256 i; i < n;) {
            for (uint256 j = i + 1; j < n;) {
                if (
                    items[i].standard == items[j].standard
                        && items[i].punkId == items[j].punkId
                ) {
                    revert DuplicateLotItem();
                }
                unchecked {
                    ++j;
                }
            }
            unchecked {
                ++i;
            }
        }

        for (uint256 i; i < n;) {
            LotItem calldata item = items[i];
            bytes32 key = _tokenKey(msg.sender, _tokenContractFor(item.standard), item.punkId);
            uint256 existingLot = lotForPunk[key];
            if (existingLot != 0) revert PunkAlreadyInLot(existingLot);
            _requirePunkInVault(item.standard, msg.sender, item.punkId);
            unchecked {
                ++i;
            }
        }
    }

    /// @dev Checks vault custody when a lot is consumed into an auction.
    function _requireLotItemsInVault(address seller, LotItem[] memory items) internal view {
        uint256 n = items.length;
        for (uint256 i; i < n;) {
            LotItem memory item = items[i];
            _requirePunkInVault(item.standard, seller, item.punkId);
            unchecked {
                ++i;
            }
        }
    }

    /// @dev Frees the per-Punk lot slots held by an items array, so the seller
    ///      can list those Punks again. Safe to call regardless of current
    ///      slot value: with first-wins, `lotForPunk[key]` for these items is
    ///      always either 0 or the lot being released.
    function _releaseLotSlots(address seller, LotItem[] memory items) internal {
        uint256 n = items.length;
        for (uint256 i; i < n;) {
            LotItem memory item = items[i];
            delete lotForPunk[_tokenKey(seller, _tokenContractFor(item.standard), item.punkId)];
            unchecked {
                ++i;
            }
        }
    }

    /// @dev Releases per-Punk lot reservations and pulls each Punk from the
    ///      seller's vault into custody.
    function _pullLotItems(address seller, LotItem[] memory items) internal {
        uint256 n = items.length;
        for (uint256 i; i < n;) {
            LotItem memory item = items[i];
            delete lotForPunk[_tokenKey(seller, _tokenContractFor(item.standard), item.punkId)];
            _pullPunk(item.standard, seller, item.punkId);
            unchecked {
                ++i;
            }
        }
    }

    /// @dev Builds the key that identifies a seller's holding of one Punk
    ///      across the `lotForPunk` reservation mapping.
    function _tokenKey(
        address seller,
        address tokenContract,
        uint256 tokenId
    ) internal pure returns (bytes32) {
        return keccak256(abi.encode(seller, tokenContract, tokenId));
    }

    /// @dev Reverts when the seller's vault does not currently hold the Punk.
    function _requirePunkInVault(
        TokenStandard standard,
        address seller,
        uint256 punkIndex
    ) internal view {
        if (!_punkInSellerVault(standard, seller, punkIndex)) revert PunkNotInVault();
    }

    // ─────────────────────────────────── Hooks ──────────────────────────────────

    function _requireAuctionApproved(address seller) internal view virtual;

    function _auctionIsApproved(address seller) internal view virtual returns (bool);

    function _punkInSellerVault(
        TokenStandard standard,
        address seller,
        uint256 punkIndex
    ) internal view virtual returns (bool);

    function _pullPunk(
        TokenStandard standard,
        address seller,
        uint256 punkIndex
    ) internal virtual;

    function _tokenContractFor(TokenStandard standard) internal view virtual returns (address);
}

project/contracts/auction/PunkPurchaseOf.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.34;

import "../interfaces/IPunksAuction.sol";
import "../interfaces/ICryptoPunksMarket.sol";
import "../interfaces/IPunksDataMatcher.sol";
import "../lib/Punks.sol";
import "../lib/PushPullEscrow.sol";

/// @title  PunkPurchaseOffers
///
/// @notice Native ETH offers for CryptoPunks with trait filters and punk bundles.
///         Bidding inspired by MouseDev's CryptoPunksBids.
///
/// @dev    The concrete auction contract supplies the market-specific purchase
///         path used when an offer is accepted.
///
/// @author VV × 1001
abstract contract PunkPurchaseOffers is IPunksAuction, PushPullEscrow {
    using Punks for Punks.Filter;

    /// @notice Maximum slots per offer.
    uint8 internal constant MAX_OFFER_SLOTS = 80;
    /// @notice Maximum number of punks to specifically include or exclude per slot.
    uint8 internal constant MAX_SLOT_IDS = 64;

    /// @notice Returns the last offer id that was created.
    uint256 public lastOfferId;

    /// @notice Returns the core data of an offer.
    /// @dev    Dynamic `slots` are read via `getOfferSlots`.
    mapping(uint256 => Offer) public offers;

    /// @notice Returns the sealed PunksData contract used for offer matching.
    IPunksDataMatcher public immutable PUNKS_DATA =
        IPunksDataMatcher(0x9cF9C8eA737A7d5157d3F4282aCe30880a7A117C);

    // ────────────────────────────────── Offers ─────────────────────────────────

    /// @inheritdoc IPunksAuction
    function placeOffer(
        uint96 amountWei,
        OfferSlot[] calldata slots
    ) external payable returns (uint256 offerId) {
        if (amountWei == 0) revert InvalidAmount();
        if (msg.value != amountWei) revert IncorrectPayment();

        uint256 slotCount = slots.length;
        if (slotCount == 0 || slotCount > MAX_OFFER_SLOTS) revert InvalidSlotCount();

        for (uint256 i; i < slotCount;) {
            _requireValidSlot(slots[i]);
            unchecked { ++i; }
        }

        unchecked { offerId = ++lastOfferId; }

        Offer storage stored = offers[offerId];
        stored.amountWei = amountWei;
        stored.offerer = msg.sender;
        _storeOfferSlots(stored, slots);

        emit OfferPlaced(
            offerId,
            msg.sender,
            amountWei,
            uint8(slotCount)
        );
        _emitOfferSlotDetails(offerId, slots);
    }

    /// @inheritdoc IPunksAuction
    function cancelOffer(uint256 offerId) external nonReentrant {
        Offer storage offer = _offerForOfferer(offerId);
        uint96 refundWei = offer.amountWei;

        delete offers[offerId];
        _pushOrCredit(msg.sender, refundWei);

        emit OfferCancelled(offerId);
    }

    /// @inheritdoc IPunksAuction
    function adjustOfferAmount(uint256 offerId, uint96 newAmountWei)
        external
        payable
        nonReentrant
    {
        if (newAmountWei == 0) revert InvalidAmount();
        Offer storage offer = _offerForOfferer(offerId);

        uint96 oldAmountWei = offer.amountWei;
        if (newAmountWei > oldAmountWei) {
            if (msg.value != newAmountWei - oldAmountWei) revert IncorrectPayment();
        } else {
            if (msg.value != 0) revert IncorrectPayment();
        }

        offer.amountWei = newAmountWei;

        if (newAmountWei < oldAmountWei) {
            _pushOrCredit(msg.sender, oldAmountWei - newAmountWei);
        }

        emit OfferAmountAdjusted(offerId, newAmountWei);
    }

    /// @inheritdoc IPunksAuction
    function acceptOffer(
        uint256 offerId,
        uint16 punkId,
        uint96 expectedListingWei
    ) external nonReentrant {
        Offer memory offer = _activeOffer(offerId);
        if (offer.slots.length != 1) revert MultiSlotOfferRequiresLot();

        OfferSlot memory slot = offer.slots[0];
        TokenStandard standard = slot.standard;
        _requireSlotMatchesPunk(slot, standard, punkId);

        ICryptoPunksMarket market = _offerMarket(standard);
        (address seller,) = _requireAcceptableListing(
            market,
            punkId,
            offer.amountWei,
            expectedListingWei
        );

        delete offers[offerId];

        address recipient = offer.offerer;
        _buyListedOfferPunk(standard, punkId, offer.amountWei, seller, recipient);

        emit OfferAccepted(
            offerId,
            punkId,
            seller,
            offer.offerer,
            offer.amountWei
        );
    }

    // ─────────────────────────────────── Views ──────────────────────────────────

    /// @inheritdoc IPunksAuction
    function getOfferSlots(uint256 offerId) external view returns (OfferSlot[] memory) {
        return offers[offerId].slots;
    }

    // ───────────────────────────────── Internals ─────────────────────────────────

    /// @dev Loads an active offer copy and reverts if it is missing.
    function _activeOffer(uint256 offerId) internal view returns (Offer memory offer) {
        offer = offers[offerId];
        if (offer.offerer == address(0)) revert OfferNotActive();
    }

    /// @dev Returns an active offer's locked amount without copying its slots,
    ///      reverting if the offer is missing.
    function _activeOfferAmount(uint256 offerId) internal view returns (uint96) {
        Offer storage offer = offers[offerId];
        if (offer.offerer == address(0)) revert OfferNotActive();
        return offer.amountWei;
    }

    /// @dev Loads the offer storage struct, ensuring the caller is the offerer.
    function _offerForOfferer(uint256 offerId)
        private
        view
        returns (Offer storage offer)
    {
        offer = offers[offerId];
        if (offer.offerer == address(0)) revert OfferNotActive();
        if (offer.offerer != msg.sender) revert NotOfferer();
    }

    /// @dev Validates a slot's filter and id-list bounds at place time.
    function _requireValidSlot(OfferSlot calldata slot) private pure {
        Punks.validate(slot.criteria);

        if (slot.includeIds.length > MAX_SLOT_IDS) revert TooManyIds();
        if (slot.excludeIds.length > MAX_SLOT_IDS) revert TooManyIds();
    }

    /// @dev Copies offer slots from calldata into storage.
    function _storeOfferSlots(Offer storage stored, OfferSlot[] calldata slots) private {
        uint256 n = slots.length;
        for (uint256 i; i < n;) {
            OfferSlot calldata src = slots[i];
            OfferSlot storage dst = stored.slots.push();
            dst.criteria = src.criteria;
            dst.standard = src.standard;
            uint256 incLen = src.includeIds.length;
            for (uint256 j; j < incLen;) {
                dst.includeIds.push(src.includeIds[j]);
                unchecked { ++j; }
            }
            uint256 excLen = src.excludeIds.length;
            for (uint256 j; j < excLen;) {
                dst.excludeIds.push(src.excludeIds[j]);
                unchecked { ++j; }
            }
            unchecked { ++i; }
        }
    }

    /// @dev Emits one OfferSlotDetail per slot at place time.
    function _emitOfferSlotDetails(uint256 offerId, OfferSlot[] calldata slots) private {
        uint256 n = slots.length;
        for (uint256 i; i < n;) {
            OfferSlot calldata s = slots[i];
            emit OfferSlotDetail(
                offerId,
                uint8(i),
                s.standard,
                s.criteria,
                s.includeIds,
                s.excludeIds
            );
            unchecked { ++i; }
        }
    }

    /// @dev Reverts unless `slots` and `items` are pairwise compatible.
    function _requireSlotsMatchItems(
        OfferSlot[] memory slots,
        LotItem[] memory items
    ) internal view {
        if (slots.length != items.length) revert SlotItemCountMismatch();
        uint256 n = items.length;
        for (uint256 i; i < n;) {
            LotItem memory item = items[i];
            _requireSlotMatchesPunk(slots[i], item.standard, item.punkId);
            unchecked { ++i; }
        }
    }

    /// @dev Reverts unless the slot matches `(standard, punkId)`.
    function _requireSlotMatchesPunk(
        OfferSlot memory slot,
        TokenStandard standard,
        uint16 punkId
    ) internal view {
        if (slot.standard != standard) revert OfferStandardMismatch();

        uint256 excludeLen = slot.excludeIds.length;
        for (uint256 i; i < excludeLen;) {
            if (slot.excludeIds[i] == punkId) revert PunkExcluded();
            unchecked { ++i; }
        }

        uint256 includeLen = slot.includeIds.length;
        for (uint256 i; i < includeLen;) {
            if (slot.includeIds[i] == punkId) return;
            unchecked { ++i; }
        }
        if (includeLen > 0 && slot.criteria.isEmpty()) revert PunkNotMatched();

        if (!slot.criteria.matches(PUNKS_DATA, punkId)) {
            revert PunkNotMatched();
        }
    }

    /// @dev Validates a Punk listing and returns its seller and price.
    function _requireAcceptableListing(
        ICryptoPunksMarket market,
        uint16 punkId,
        uint96 amountWei,
        uint96 expectedListingWei
    ) internal view returns (address seller, uint256 listingWei) {
        (bool isForSale,, address listingSeller, uint256 minValue, address onlySellTo) =
            market.punksOfferedForSale(punkId);

        if (
            !isForSale
                || listingSeller == address(0)
                || (onlySellTo != address(0) && onlySellTo != address(this))
        ) {
            revert ListingNotValid();
        }
        if (market.punkIndexToAddress(punkId) != listingSeller) revert ListingNotValid();
        if (minValue != expectedListingWei) {
            revert ListingPriceMismatch(expectedListingWei, minValue);
        }
        if (minValue > amountWei) revert ListingPriceTooHigh();

        return (listingSeller, minValue);
    }

    /// @dev Resolves the Punk market for an offer standard.
    function _offerMarket(TokenStandard standard)
        internal
        view
        virtual
        returns (ICryptoPunksMarket);

    /// @dev Buys a listed Punk and sends it to the final recipient.
    function _buyListedOfferPunk(
        TokenStandard standard,
        uint16 punkId,
        uint256 purchaseWei,
        address seller,
        address recipient
    ) internal virtual;
}

